export async function generateAIPostText(theme: string, message: string): Promise<string> {
    return new Promise((resolve) => {
        setTimeout(() => {
            resolve(
                `縲・{theme}縲曾
\n${message}\n\n#縺顔衍繧峨○ #繧｢繝・・繝・・繝・
            );
        }, 1500); // 繝｢繝・け縺ｮ驕・ｻｶ
    });
}

export async function generateAIImage(prompt: string): Promise<string> {
    return new Promise((resolve) => {
        setTimeout(() => {
            // Unsplash縺ｮ繝励Ξ繝ｼ繧ｹ繝帙Ν繝繝ｼ逕ｻ蜒上ｒ霑斐☆
            resolve(\`https://source.unsplash.com/random/800x600/?\${encodeURIComponent(prompt)}\`);
    }, 2000);
  });
}

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Sparkles, Image as ImageIcon, Send, Save, Loader2 } from 'lucide-react';
import { usePostStore } from '../stores/usePostStore';
import { Platform } from '../types';
import { generateAIPostText, generateAIImage } from '../lib/api';

export function CreatePost() {
    const navigate = useNavigate();
    const addPost = usePostStore((state) => state.addPost);

    const [theme, setTheme] = useState('');
    const [message, setMessage] = useState('');
    const [content, setContent] = useState('');
    const [imageUrl, setImageUrl] = useState('');
    const [platforms, setPlatforms] = useState<Platform[]>(['x']);
    const [isGeneratingText, setIsGeneratingText] = useState(false);
    const [isGeneratingImage, setIsGeneratingImage] = useState(false);
    const [scheduledAt, setScheduledAt] = useState('');

    const handleGenerateText = async () => {
        if (!theme || !message) {
            alert('繝・・繝槭→莨昴∴縺溘＞縺薙→繧貞・蜉帙＠縺ｦ縺上□縺輔＞');
            return;
        }
        setIsGeneratingText(true);
        try {
            const generated = await generateAIPostText(theme, message);
            setContent(generated);
        } catch (error) {
            console.error(error);
            alert('逕滓・縺ｫ螟ｱ謨励＠縺ｾ縺励◆');
        } finally {
            setIsGeneratingText(false);
        }
    };

    const handleGenerateImage = async () => {
        if (!theme) {
            alert('逕ｻ蜒冗函謌舌・繝励Ο繝ｳ繝励ヨ縺ｨ縺励※繝・・繝槭ｒ蜈･蜉帙＠縺ｦ縺上□縺輔＞');
            return;
        }
        setIsGeneratingImage(true);
        try {
            const url = await generateAIImage(theme);
            setImageUrl(url);
        } catch (error) {
            console.error(error);
            alert('逕ｻ蜒冗函謌舌↓螟ｱ謨励＠縺ｾ縺励◆');
        } finally {
            setIsGeneratingImage(false);
        }
    };

    const togglePlatform = (p: Platform) => {
        setPlatforms((prev) =>
            prev.includes(p) ? prev.filter((item) => item !== p) : [...prev, p]
        );
    };

    const handleSaveDraft = () => {
        if (!content) {
            alert('謚慕ｨｿ蜀・ｮｹ縺後≠繧翫∪縺帙ｓ');
            return;
        }
        addPost({
            theme,
            message,
            content,
            imageUrl,
            platforms,
            status: 'draft',
            scheduledAt: scheduledAt || undefined,
        });
        alert('荳区嶌縺阪ｒ菫晏ｭ倥＠縺ｾ縺励◆');
        navigate('/posts');
    };

    const handleSchedulePost = () => {
        if (!content) {
            alert('謚慕ｨｿ蜀・ｮｹ縺後≠繧翫∪縺帙ｓ');
            return;
        }
        if (!scheduledAt) {
            alert('莠育ｴ・律譎ゅｒ謖・ｮ壹＠縺ｦ縺上□縺輔＞');
            return;
        }
        if (platforms.length === 0) {
            alert('謚慕ｨｿ蜈医・繝ｩ繝・ヨ繝輔か繝ｼ繝繧・縺､莉･荳企∈謚槭＠縺ｦ縺上□縺輔＞');
            return;
        }
        addPost({
            theme,
            message,
            content,
            imageUrl,
            platforms,
            status: 'scheduled',
            scheduledAt,
        });
        alert('謚慕ｨｿ繧剃ｺ育ｴ・＠縺ｾ縺励◆');
        navigate('/posts');
    };

    return (
        <div className="max-w-4xl mx-auto space-y-6 animate-in fade-in duration-300">
            <div className="flex items-center justify-between">
                <h1 className="text-2xl font-bold text-slate-800">譁ｰ隕乗兜遞ｿ縺ｮ菴懈・</h1>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                {/* 蟾ｦ蛛ｴ: 蜈･蜉帙→逕滓・ */}
                <div className="space-y-6">
                    <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                        <h2 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
                            <Sparkles className="w-5 h-5 text-indigo-500" />
                            謚慕ｨｿ縺ｮ隕∽ｻｶ
                        </h2>

                        <div className="space-y-4">
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">繝・・繝・/label>
                                <input
                                    type="text"
                                    value={theme}
                                    onChange={(e) => setTheme(e.target.value)}
                                    className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all"
                                    placeholder="萓・ 譁ｰ讖溯・繝ｪ繝ｪ繝ｼ繧ｹ縺ｮ縺顔衍繧峨○"
                                />
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">莨昴∴縺溘＞縺薙→</label>
                                <textarea
                                    value={message}
                                    onChange={(e) => setMessage(e.target.value)}
                                    className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all min-h-[120px] resize-none"
                                    placeholder="萓・ 繝ｦ繝ｼ繧ｶ繝ｼ縺ｮ隕∵悍縺悟､壹°縺｣縺溘ム繝・す繝･繝懊・繝画ｩ溯・繧呈僑蜈・＠縺ｾ縺励◆縲・
